insight.code_example:
mutation {
  marketCreate(
    input: {
      name: "US Market"
      currencyCode: USD
      shippingZones: [
        {
          zone: {
            name: "Contiguous US"
            countries: [US]
            provinces: []
          }
          shippingRates: [
            {
              price: "10.00"
              weightRange: {
                max: 10
                min: 0
              }
            }
          ]
        }
      ]
    }
  ) {
    market {
      id
    }
    userErrors {
      field
      message
    }
  }
}
